constexpr size_t kStaticChunkSize = 4096;
constexpr unsigned int kBlockSize = 256;

template <typename T>
__device__ inline void atomic_add_compat(T* addr, T val);

template <>
__device__ inline void atomic_add_compat<int>(int* addr, int val) {
  atomicAdd(addr, val);
}

template <>
__device__ inline void atomic_add_compat<float>(float* addr, float val) {
  atomicAdd(addr, val);
}

template <>
__device__ inline void atomic_add_compat<double>(double* addr, double val) {
#if __CUDA_ARCH__ >= 600
  atomicAdd(addr, val);
#else
  unsigned long long int* address_as_ull =
      reinterpret_cast<unsigned long long int*>(addr);
  unsigned long long int old = *address_as_ull, assumed;
  do {
    assumed = old;
    old = atomicCAS(address_as_ull, assumed,
                    __double_as_longlong(val +
                                         __longlong_as_double(assumed)));
  } while (assumed != old);
#endif
}

template <typename T, unsigned int compute_iterations, unsigned int BLOCK_SIZE>
__global__ void bench_kernel(T* data, size_t len, T* global_sum) {
  __shared__ T sdata[BLOCK_SIZE];

  const size_t num_chunks = (len + kStaticChunkSize - 1) / kStaticChunkSize;
  T thread_sum = 0;

  for (size_t chunk = blockIdx.x; chunk < num_chunks; chunk += gridDim.x) {
    const size_t base = chunk * kStaticChunkSize;
    const size_t chunk_len =
        (base + kStaticChunkSize <= len) ? kStaticChunkSize : (len - base);

#ifdef BASELINE_IMPL
    const T f = (chunk_len > 0) ? data[base] : T(0);

    for (size_t i = threadIdx.x; i < chunk_len; i += BLOCK_SIZE) {
      T t = data[base + i];
#pragma unroll
      for (unsigned int j = 0; j < compute_iterations; ++j) {
        t = t * t + f;
      }
      thread_sum += t;
    }
#else
    const T f0 = (chunk_len > 0) ? data[base + 0] : T(0);
    const T f1 = (chunk_len > 1) ? data[base + 1] : T(0);
    const T f2 = (chunk_len > 2) ? data[base + 2] : T(0);
    const T f3 = (chunk_len > 3) ? data[base + 3] : T(0);
    const T f4 = (chunk_len > 4) ? data[base + 4] : T(0);
    const T f5 = (chunk_len > 5) ? data[base + 5] : T(0);
    const T f6 = (chunk_len > 6) ? data[base + 6] : T(0);
    const T f7 = (chunk_len > 7) ? data[base + 7] : T(0);

    for (size_t i = threadIdx.x; i < chunk_len; i += BLOCK_SIZE) {
      const T v = data[base + i];
      T t0 = v, t1 = v, t2 = v, t3 = v, t4 = v, t5 = v, t6 = v, t7 = v;

#pragma unroll
      for (unsigned int j = 0; j < (compute_iterations / 8); ++j) {
        t0 = t0 * t0 + f0;
        t1 = t1 * t1 + f1;
        t2 = t2 * t2 + f2;
        t3 = t3 * t3 + f3;
        t4 = t4 * t4 + f4;
        t5 = t5 * t5 + f5;
        t6 = t6 * t6 + f6;
        t7 = t7 * t7 + f7;
      }
      if (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
      if (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
      if (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
      if (compute_iterations % 8 > 3) t3 = t3 * t3 + f3;
      if (compute_iterations % 8 > 4) t4 = t4 * t4 + f4;
      if (compute_iterations % 8 > 5) t5 = t5 * t5 + f5;
      if (compute_iterations % 8 > 6) t6 = t6 * t6 + f6;

      thread_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
    }
#endif
  }

  sdata[threadIdx.x] = thread_sum;
  __syncthreads();

  for (unsigned int s = BLOCK_SIZE / 2; s > 0; s >>= 1) {
    if (threadIdx.x < s) {
      sdata[threadIdx.x] += sdata[threadIdx.x + s];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    atomic_add_compat(global_sum, sdata[0]);
  }
}

template <typename T, unsigned int compute_iterations>
void bench_device(size_t len, T* d_src, void* d_sum_bytes, int grid_size) {
  T* d_sum = reinterpret_cast<T*>(d_sum_bytes);
  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(T)));
  bench_kernel<T, compute_iterations, kBlockSize>
      <<<grid_size, kBlockSize>>>(d_src, len, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());
  CUDA_SAFE_CALL(
      cudaMemcpyAsync(d_src, d_sum, sizeof(T), cudaMemcpyDeviceToDevice));
}

template <typename Op>
double measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, start, stop));
  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));
  return static_cast<double>(ms);
}

template <typename Op>
double benchmark_gpu(Op op) {
  constexpr int total_runs = 20;

  (void)op();
  std::vector<double> measurements;
  measurements.reserve(total_runs - 1);

  for (int i = 1; i < total_runs; ++i) {
    measurements.push_back(op());
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t data_0, int compute_iterations)
      : memory_space_{data_0}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

static int choose_grid_size(size_t len) {
  size_t num_chunks = (len + kStaticChunkSize - 1) / kStaticChunkSize;
  cudaDeviceProp prop;
  int dev = 0;
  CUDA_SAFE_CALL(cudaGetDevice(&dev));
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&prop, dev));
  int grid = prop.multiProcessorCount * 32;
  if (grid < 1) grid = 1;
  if (num_chunks > 0 && static_cast<size_t>(grid) > num_chunks) {
    grid = static_cast<int>(num_chunks);
  }
  if (grid < 1) grid = 1;
  return grid;
}

double runbench_warmup(void* d_data, size_t size_bytes, void* d_sum_bytes) {
  const size_t num_elements = size_bytes / sizeof(double);
  const int grid_size = choose_grid_size(num_elements);
  return measure_operation([&] {
    bench_device<double, 16>(num_elements, reinterpret_cast<double*>(d_data),
                             d_sum_bytes, grid_size);
  });
}

template <unsigned int compute_iterations>
void runbench(void* d_data_void, size_t size_bytes, void* d_sum_bytes) {
  ComputeSpace cs{size_bytes, static_cast<int>(compute_iterations)};

  float* d_float = reinterpret_cast<float*>(d_data_void);
  const int grid_sp = choose_grid_size(cs.element_count<float>());
  auto kernel_time_mad_sp = benchmark_gpu([&] {
    return measure_operation([&] {
      bench_device<float, compute_iterations>(cs.element_count<float>(), d_float,
                                              d_sum_bytes, grid_sp);
    });
  });

  double* d_double = reinterpret_cast<double*>(d_data_void);
  const int grid_dp = choose_grid_size(cs.element_count<double>());
  auto kernel_time_mad_dp = benchmark_gpu([&] {
    return measure_operation([&] {
      bench_device<double, compute_iterations>(
          cs.element_count<double>(), d_double, d_sum_bytes, grid_dp);
    });
  });

  int* d_int = reinterpret_cast<int*>(d_data_void);
  const int grid_int = choose_grid_size(cs.element_count<int>());
  auto kernel_time_mad_int = benchmark_gpu([&] {
    return measure_operation([&] {
      bench_device<int, compute_iterations>(cs.element_count<int>(), d_int,
                                            d_sum_bytes, grid_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000.0 / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000.0 / (1000.0 * 1000.0 * 1000.0)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000.0 / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000.0 / (1000.0 * 1000.0 * 1000.0)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000.0 / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000.0 / (1000.0 * 1000.0 * 1000.0)

            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* d_data, size_t size_bytes, void* d_sum_bytes) {
  runbench<compute_iterations>(d_data, size_bytes, d_sum_bytes);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* d_data, size_t size_bytes, void* d_sum_bytes) {
  runbench_range<j1>(d_data, size_bytes, d_sum_bytes);
  runbench_range<j2, Args...>(d_data, size_bytes, d_sum_bytes);
}

