  void* d_data = nullptr;
  void* d_sum_bytes = nullptr;

  CUDA_SAFE_CALL(cudaMalloc(&d_data, size_bytes));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_bytes, sizeof(double)));
